function o(){return Array.from(document.querySelectorAll("video"))[0]||null}chrome.runtime.onMessage.addListener((n,c,t)=>{if(n.type==="capture-frame"){const i=o();if(!i){t({image:null});return}const e=document.createElement("canvas");e.width=i.videoWidth,e.height=i.videoHeight;const r=e.getContext("2d");if(!r){t({image:null});return}r.drawImage(i,0,0,e.width,e.height);const a=e.toDataURL("image/png");t({image:a})}else t({image:null})});
